app.get('/auth/kick/callback',async(req,res)=>{const a=oauth.get(req.query.state);if(!a||a.expires<Date.now())return res.status(400).send(page('Sign-in expired','<p>Please start again.</p><a class="button" href="/login">Return to sign in</a>'));oauth.delete(req.query.state);const response=await fetch('https://id.kick.com/oauth/token',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({grant_type:'authorization_code',client_id:process.env.KICK_CLIENT_ID,client_secret:process.env.KICK_CLIENT_SECRET,redirect_uri:`${BASE}/auth/kick/callback`,code_verifier:a.verifier,code:req.query.code})}),tokens=await response.json();if(!response.ok)return res.status(400).send(page('Kick sign-in failed','<p>Kick did not authorize the request.</p><a class="button" href="/login">Try again</a>'));let tenantId=a.tenant,kickUser=null;if(a.flow==='login'){const userResponse=await fetch('https://api.kick.com/public/v1/users',{headers:{Authorization:`Bearer ${tokens.access_token}`}}),userBody=await userResponse.json().catch(()=>({}));kickUser=Array.isArray(userBody.data)?userBody.data[0]:userBody.data||userBody;if(!userResponse.ok||!kickUser)return res.status(400).send(page('Could not read Kick account','<p>Please ensure account access is allowed, then try again.</p>'));const kickId=String(kickUser.user_id||kickUser.id||''),channel=norm(kickUser.name||kickUser.username||'').replace(/ /g,''),match=(await pool.query('SELECT id FROM tenants WHERE kick_user_id=$1 OR channel_name=$2 LIMIT 1',[kickId,channel])).rows[0];if(!match)return res.status(403).send(page('No beta account found',`<p>Your Kick account is not linked to a registered beta channel.</p><a class="button" href="/join">Join private beta</a>`));tenantId=match.id}await pool.query('UPDATE tenants SET kick_user_id=COALESCE($2,kick_user_id),kick_access_token=$3,kick_refresh_token=$4,kick_token_expires_at=$5,updated_at=NOW() WHERE id=$1',[tenantId,kickUser?String(kickUser.user_id||kickUser.id||''):null,encrypt(tokens.access_token),tokens.refresh_token?encrypt(tokens.refresh_token):null,Date.now()+Number(tokens.expires_in||3600)*1000]);try{await ensureSubscription({id:tenantId,kick_access_token:encrypt(tokens.access_token)},tokens.access_token)}catch(error){if(a.flow!=='login')return res.status(400).send(page('Kick connected','<p>The account connected, but the chat subscription could not be created. Please try reconnecting.</p>'))}if(a.flow==='login'){const session=token();await pool.query('UPDATE tenants SET session_token_hash=$2 WHERE id=$1',[tenantId,hash(session)]);res.setHeader('Set-Cookie',sessionCookie(session))}res.redirect('/dashboard')});
app.post('/webhooks/kick',async(req,res)=>{const raw=req.body.toString('utf8');if(!verify(req,raw))return res.sendStatus(403);const id=req.headers['kick-event-message-id'];try{await pool.query('INSERT INTO webhook_messages(message_id) VALUES($1)',[id])}catch{return res.json({duplicate:true})}const e=JSON.parse(raw),channel=norm(e.broadcaster?.username||e.broadcaster?.user_name||'').replace(/ /g,''),t=(await pool.query('SELECT * FROM tenants WHERE channel_name=$1',[channel])).rows[0];if(t&&req.headers['kick-event-type']==='chat.message.sent')await message(t,e.sender.username,e.content,e.sender.user_id);res.json({received:true})});
app.get('/o/:token/events',async(req,res)=>{const t=await tenantByOverlay(req.params.token);if(!t)return res.sendStatus(404);res.set({'Content-Type':'text/event-stream','Cache-Control':'no-cache','Connection':'keep-alive'});if(!streams.has(t.id))streams.set(t.id,new Set());streams.get(t.id).add(res);res.write(`data: ${JSON.stringify(await state(t))}\n\n`);req.on('close',()=>streams.get(t.id)?.delete(res))});
app.get('/o/:token/state',async(req,res)=>{const t=await tenantByOverlay(req.params.token);if(!t)return res.sendStatus(404);res.json(await state(t))});
app.get('/o/:token/overlay.html',async(req,res)=>{if(!await tenantByOverlay(req.params.token))return res.sendStatus(404);res.sendFile(path.join(__dirname,'public','overlay.html'))});
app.get('/o/:token/scoreboard.html',async(req,res)=>{if(!await tenantByOverlay(req.params.token))return res.sendStatus(404);res.sendFile(path.join(__dirname,'public','scoreboard.html'))});
app.get('/o/:token/test',async(req,res)=>{const t=await tenantByOverlay(req.params.token);if(!t)return res.sendStatus(404);await startRound(t);res.redirect(`/o/${t.overlay_token}/overlay.html`)});
setInterval(async()=>{const due=(await pool.query('SELECT * FROM tenants WHERE kick_access_token IS NOT NULL AND COALESCE(next_round_at,0)<=$1',[Date.now()])).rows;for(const t of due)if(gameSettings(t.settings).automatic)await startRound(t)},30000);
setInterval(async()=>{const active=(await pool.query("SELECT * FROM guest_sessions WHERE revoked_at IS NULL AND expires_at>NOW() AND settings->>'automatic'='true'")).rows;for(const session of active){if(Number(session.settings?.nextAutoAt||0)<=Date.now()){await startGuestRound(session,Math.random()<.2);session.settings={...(session.settings||{}),nextAutoAt:Date.now()+45000};await pool.query('UPDATE guest_sessions SET settings=$2,updated_at=NOW() WHERE id=$1',[session.id,JSON.stringify(session.settings)])}}for(const[id,responses]of guestStreams){const alive=active.some(session=>session.id===id)||(await pool.query('SELECT 1 FROM guest_sessions WHERE id=$1 AND revoked_at IS NULL AND expires_at>NOW()',[id])).rowCount;if(!alive){for(const response of responses)response.end();guestStreams.delete(id);guestRounds.delete(id)}}},15000);
setTimeout(()=>maintainKickConnections().catch(console.error),15000);setInterval(()=>maintainKickConnections().catch(console.error),300000);
function escapeHtml(value){return String(value).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}function copy(label,value){return`<div class="copy"><b>${label}</b><code>${value}</code><button onclick="navigator.clipboard.writeText('${value}')">Copy</button></div>`}function page(title,body){return`<!doctype html><meta name="viewport" content="width=device-width"><title>${title}</title><style>body{margin:0;background:#070a08;color:#fff;font:16px system-ui}a{color:#53fc18}main{max-width:820px;margin:50px auto;padding:28px}h1{font-size:42px}h1,h2{color:#fff}.status,.copy,form,.guide{padding:18px;margin:14px 0;border:1px solid #334238;border-radius:14px;background:#101712}.status{color:#53fc18;font-weight:800}.account{display:flex;justify-content:space-between;align-items:center;color:#9cab9f;margin:-8px 0 20px}.account a{font-weight:800}.maintenance{display:grid;gap:4px;padding:13px 16px;border:1px solid #304f36;border-radius:12px;background:#0b160e;color:#53fc18}.maintenance span{color:#9cab9f;font-size:12px}label{display:grid;gap:7px;margin:14px 0}input,textarea{padding:13px;border:1px solid #415045;border-radius:9px;background:#080b09;color:#fff}.button,button{display:inline-block;padding:12px 16px;border:0;border-radius:9px;background:#53fc18;color:#071006;font-weight:900;text-decoration:none;cursor:pointer}.secondary{margin-left:8px;background:#253029;color:#fff}.copy{display:grid;grid-template-columns:130px 1fr auto;gap:12px;align-items:center}.copy code{overflow:hidden;text-overflow:ellipsis;color:#b7c5bb}.guide{margin-top:28px;padding:26px}.guide h2{font-size:27px;margin:10px 0 4px}.guide ol{padding-left:25px}.guide li{margin:12px 0;line-height:1.5}.muted{color:#9cab9f}.pill{display:inline-flex;padding:5px 10px;border-radius:99px;background:#253029;color:#53fc18;font-size:12px;font-weight:800;letter-spacing:.08em}.commands{display:grid;grid-template-columns:1fr 1fr;gap:9px;margin:18px 0}.commands div{display:grid;gap:4px;padding:13px;border-radius:11px;background:#0a0f0c}.commands code{color:#53fc18;font-weight:900}.commands span{color:#9cab9f;font-size:13px}.panel img{display:block;width:min(100%,420px);max-height:630px;object-fit:contain;margin:20px auto;border-radius:14px;border:1px solid #334238}.panel-actions{display:flex;flex-wrap:wrap;gap:8px}.panel-actions .secondary{margin:0}.panel textarea{min-height:90px;resize:vertical;line-height:1.45}@media(max-width:650px){.copy,.commands{grid-template-columns:1fr}main{margin:10px}.secondary{margin:10px 0 0}.account{align-items:flex-start;gap:10px}}</style><main><small style="color:#53fc18;letter-spacing:.18em">EMOJI DECODER CLOUD BETA</small><h1>${title}</h1>${body}</main>`}
